/// <summary>
/// extension of class <c>LedgerJournalWFApprSubmitToWF</c>
/// </summary>
[ExtensionOf(classStr(LedgerJournalWFApprSubmitToWF))]
internal final class ETGLedgerJournalWFApprSubmitToWF_Extension
{
}

Method.Source:
 protected void run()
{
    //NS, DLT, 25032025, Invoice journal creator will validate the ledger and the approval will approve and post the entries.
    //validate ledger journal workflow. check simulate posting is having any error or not
    //stop submit workflow in case any error found in simulate posting
    next run();

    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        if(args.record() && args.record().TableId == tableNum(LedgerJournalTable))
        {
            LedgerJournalTable ledgerJournalTableETG = args.record();

            MenuFunction    menuFunction;

            menuFunction = new MenuFunction(menuitemActionStr(LedgerJournalSimPost), MenuItemType::Action);

            if (menuFunction && menuFunction.checkAccessRights())
            {
                menuFunction.run(args);
            }

        }
    }
    //NE, DLT, 25032025, Invoice journal creator will validate the ledger and the approval will approve and post the entries.
}
